import{_ as t,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"70. Definitions Specific To Section 2","description":"","frontmatter":{"title":"70. Definitions Specific To Section 2","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.md","filePath":"ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.md"}'),i={name:"ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.md"};function s(a,e,p,c,l,h){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_70-definitions-specific-to-section-2" tabindex="-1">70. Definitions Specific To Section 2 <a class="header-anchor" href="#_70-definitions-specific-to-section-2" aria-label="Permalink to &quot;70. Definitions Specific To Section 2&quot;">​</a></h1><p><strong>70.1</strong> The following definitions will apply in Section 2 of the Agreement:</p><p><strong>(a)</strong> IQN means Internationally Qualified Nurse</p><p><strong>(b)</strong> shift worker, for the purposes of the NES, means an Employee who is rostered and works over seven days of the week throughout the qualifying 12 months period of service</p><p><strong>(c)</strong> Experience means paid service whether in Australia or internationally as a registered nurse, or enrolled nurse, following registration by the professional registration body, in a grade in which the Employee is, or is about to be, employed except:</p><p><strong>(i)</strong> where an IQN is granted registration with conditions, previous experience will not be counted whilst the conditions are in place. Experience as defined will count once there are no longer conditions in place:</p><p><strong>(ii)</strong> where an IQN is granted registration subject to successful completion of a bridging program previous experience will not be counted</p><p><strong>(iii)</strong> where an IQN is required by the Australian professional registration body to undertake an outcome-based assessment (OBA) previous experience will not be counted.</p><p><strong>(d)</strong> a Year of Experience in this Agreement means:</p><p><strong>(i)</strong> an average of three shifts or more per week in a year. If the Employee averages less than three shifts per week or 48 hours per fortnight (whichever is the lesser), the Employee will need to complete an additional year to advance</p><p><strong>(ii)</strong> in the case of an IQN registering in Australia for the first time who was not required by the Australian professional registration body to undertake either a bridging program or outcome-based assessment (OBA), a Year of Experience means: <strong>(A)</strong> an average of at least 48 hours per fortnight; and <strong>(B)</strong> for each year in which the IQN averages less than 48 hours per fortnight, the Employee will need to complete an additional year to advance.</p><p><strong>(iii)</strong> For the purpose of being classified under this Agreement, upon commencement with an Employer: <strong>(A)</strong> subject to (iv) below, an Employee&#39;s anniversary date is the date the Employee commenced work as a Registered Nurse or Enrolled Nurse following registration either in Australia or internationally; or <strong>(B)</strong> in the case of an IQN required to undertake a bridging program or outcome-based assessment (OBA) in order to be registered in</p><p>Australia, the date the Employee commenced work as a Registered Nurse or Enrolled Nurse following registration in Australia</p><p><strong>(iv)</strong> For the purpose of experience advancement under this Agreement, upon commencement with an Employer: <strong>(A)</strong> an Employee’s anniversary date is the date the Employee commenced work as a registered nurse, or enrolled nurse following registration either in Australia or internationally (subject to clause 70.1(d)(i)); <strong>(B)</strong> Years of Experience are relevant to determining the appropriate increment within a Grade, Years of Experience are calculated from the Employees anniversary date; and <strong>(C)</strong> the onus is on the Employee to demonstrate the completed Years of Experience and anniversary date. The Employer may require evidence that would satisfy a reasonable person of the claimed experience with the previous Employer/s.</p><p><strong>(v)</strong> Experience can be with concurrent Employer/s, on provision by the Employee of evidence of experience with other Employer/s save that: <strong>(A)</strong> Any new increment is payable from the FFPPOOA, the evidence is provided; and <strong>(B)</strong> Notwithstanding this term, any previously recognised concurrent service is unaffected by this term. Note: Experience and Years of Experience are only relevant to determining what constitutes experience (including previous experience) for the purpose of incremental progression through an Employee’s classification.</p><p><strong>(e)</strong> In Section 2 of the Agreement, allowances will be calculated to the nearest 10 cents, an exact amount of 5 cents in the result going to the higher figure, unless otherwise specified.</p>',16)])])}const m=t(i,[["render",s]]);export{g as __pageData,m as default};
